from datetime import datetime
from openpyxl import load_workbook
from copy import copy  # Import copy module for style copying

# Get today's date to match the filenames generated by other scripts
current_date = datetime.now().strftime("%m-%d-%y")

# Define file paths
file1 = f"_results/Big_Numbers_DATA/Big_Numbers_UF_{current_date}.xlsx"
file2 = f"_results/SE_COMPLETA_2023-24_DATA/SE_COMPLETA_2023-24_{current_date}.xlsx"
file3 = f"_results/Informe_Semana_Epidemiologica_DATA/Informe_Semana_Epidemiologica_{current_date}.xlsx"
output_file = f"_results/_final_output/Epidemiology_Dengue_{current_date}.xlsx"

# Function to copy worksheet preserving formatting and filters
def copy_worksheet(old_sheet, new_book, sheet_name):
    new_sheet = new_book.create_sheet(sheet_name)
    
    # Copy cell values, styles, and formatting
    for row in old_sheet.rows:
        for cell in row:
            new_cell = new_sheet[cell.coordinate]
            new_cell.value = cell.value
            if cell.has_style:
                new_cell.font = copy(cell.font)              # Updated to use copy.copy()
                new_cell.border = copy(cell.border)          # Updated to use copy.copy()
                new_cell.fill = copy(cell.fill)              # Updated to use copy.copy()
                new_cell.number_format = cell.number_format  # This doesn't need copying
                new_cell.protection = copy(cell.protection)  # Updated to use copy.copy()
                new_cell.alignment = copy(cell.alignment)    # Updated to use copy.copy()

    # Copy column widths
    for col in old_sheet.column_dimensions:
        new_sheet.column_dimensions[col].width = old_sheet.column_dimensions[col].width

    # Copy row heights
    for row in old_sheet.row_dimensions:
        new_sheet.row_dimensions[row].height = old_sheet.row_dimensions[row].height

    # Copy filters
    if old_sheet.auto_filter.ref:  # Check if filter exists
        new_sheet.auto_filter.ref = old_sheet.auto_filter.ref

# Load source workbooks with error handling
try:
    wb1 = load_workbook(file1)
    wb2 = load_workbook(file2)
    wb3 = load_workbook(file3)

    # Create new workbook
    new_wb = load_workbook(filename=file1)  # Start with first file as template
    new_wb.remove(new_wb.active)  # Remove default sheet

    # Copy sheets
    copy_worksheet(wb1.active, new_wb, "Big_Numbers_UF")
    copy_worksheet(wb2.active, new_wb, "SE_COMPLETA_2023-24")
    copy_worksheet(wb3.active, new_wb, "Informe_Semana_Epidemiologica")

    # Save the merged workbook
    new_wb.save(output_file)
    print(f"Merged file saved as '{output_file}'")

except FileNotFoundError as e:
    print(f"Error: One of the input files was not found - {e}")
except Exception as e:
    print(f"An error occurred: {e}")